const data = $json.body;
const telefone = data.telefone;
const nome = data.nome;

const OFFSET_MS = 3 * 60 * 60 * 1000;
const agora = new Date();

const agoraBRT = new Date(agora.getTime() - OFFSET_MS);
const amanhaBRT = new Date(agoraBRT);
amanhaBRT.setDate(amanhaBRT.getDate() + 1);
amanhaBRT.setHours(0, 0, 0, 0);

const inicioJanela = new Date(amanhaBRT.getTime() + OFFSET_MS);
const fimJanela = new Date(inicioJanela.getTime() + 7 * 24 * 60 * 60 * 1000);

return [{
  json: {
    telefone,
    nome,
    janelaInicio: inicioJanela.toISOString(),
    janelaFim: fimJanela.toISOString()
  }
}];

const OFFSET_MS = 3 * 60 * 60 * 1000;
const DURACAO_MS = 60 * 60 * 1000;

const BUSINESS = {
  1: [9, 30, 22, 30],
  2: [9, 30, 22, 30],
  3: [9, 30, 22, 30],
  4: [9, 30, 22, 30],
  5: [9, 30, 22, 30],
  6: [9, 30, 17, 0]
};

const preparaData = $('Prepara Janela').first().json;
const telefone = preparaData.telefone;
const nome = preparaData.nome;
const janelaInicio = new Date(preparaData.janelaInicio);
const janelaFim = new Date(preparaData.janelaFim);

const googleResp = $('FreeBusy Google Calendar').first().json;
const googleCal = (googleResp.calendars && (googleResp.calendars['wostki@gmail.com'] || googleResp.calendars.primary)) || {};
const googleBusy = (googleCal.busy || []).map(b => ({ start: b.start, end: b.end }));

// Nespon: se dateTime ja tem timezone (Z ou +/-HH:MM), usar direto; se nao, +3h (BRT como UTC)
function adjustNespon(obj) {
  const dateStr = obj.dateTime || obj.date;
  if (!dateStr) return null;
  const ms = new Date(dateStr).getTime();
  if (!obj.timeZone || obj.timeZone === 'UTC') return ms + OFFSET_MS;
  return ms;
}

const nesponEvents = $('Get Nespon Events').all();
const nesponBusy = nesponEvents
  .filter(e => e.json && e.json.start && e.json.end)
  .map(e => {
    const startMs = adjustNespon(e.json.start);
    const endMs = adjustNespon(e.json.end);
    if (!startMs || !endMs) return null;
    return {
      start: new Date(startMs).toISOString(),
      end:   new Date(endMs).toISOString()
    };
  })
  .filter(Boolean);

const allBusy = [...googleBusy, ...nesponBusy];

function isBusy(slotStart, slotEnd) {
  return allBusy.some(b => {
    const bs = new Date(b.start).getTime();
    const be = new Date(b.end).getTime();
    return slotStart.getTime() < be && slotEnd.getTime() > bs;
  });
}

function toBRT(utcDate) { return new Date(utcDate.getTime() - OFFSET_MS); }
function toUTC(brtDate) { return new Date(brtDate.getTime() + OFFSET_MS); }

const DIAS = ['Dom', 'Seg', 'Ter', 'Qua', 'Qui', 'Sex', 'Sab'];
const MESES = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];

const slots = [];
let cursor = new Date(janelaInicio);

while (cursor < janelaFim && slots.length < 3) {
  const brtCursor = toBRT(cursor);
  const diaSemana = brtCursor.getDay();

  if (!BUSINESS[diaSemana]) {
    const brtNextDay = new Date(brtCursor);
    brtNextDay.setDate(brtNextDay.getDate() + 1);
    brtNextDay.setHours(0, 0, 0, 0);
    cursor = toUTC(brtNextDay);
    continue;
  }

  const [hIni, mIni, hFim, mFim] = BUSINESS[diaSemana];
  const brtDay = new Date(brtCursor);
  brtDay.setHours(0, 0, 0, 0);

  const brtIniExp = new Date(brtDay);
  brtIniExp.setHours(hIni, mIni, 0, 0);
  const brtFimExp = new Date(brtDay);
  brtFimExp.setHours(hFim, mFim, 0, 0);

  if (brtCursor < brtIniExp) {
    cursor = toUTC(brtIniExp);
    continue;
  }

  if (brtCursor >= brtFimExp) {
    const brtNextDay = new Date(brtDay);
    brtNextDay.setDate(brtNextDay.getDate() + 1);
    brtNextDay.setHours(0, 0, 0, 0);
    cursor = toUTC(brtNextDay);
    continue;
  }

  const slotStart = new Date(cursor);
  const slotEnd = new Date(cursor.getTime() + DURACAO_MS);

  if (slotEnd > toUTC(brtFimExp)) {
    const brtNextDay = new Date(brtDay);
    brtNextDay.setDate(brtNextDay.getDate() + 1);
    brtNextDay.setHours(0, 0, 0, 0);
    cursor = toUTC(brtNextDay);
    continue;
  }

  if (!isBusy(slotStart, slotEnd)) {
    const brtStart = toBRT(slotStart);
    const label = DIAS[brtStart.getDay()] + ' ' +
                  String(brtStart.getDate()).padStart(2, '0') + '/' +
                  MESES[brtStart.getMonth()] + ' as ' +
                  String(brtStart.getHours()).padStart(2, '0') + ':' +
                  String(brtStart.getMinutes()).padStart(2, '0') + 'h';
    slots.push({
      isoUTC: slotStart.toISOString(),
      isoFimUTC: slotEnd.toISOString(),
      label
    });
  }

  cursor = new Date(cursor.getTime() + 30 * 60 * 1000);
}

if (slots.length === 0) {
  throw new Error('Nenhum slot disponivel na janela de 7 dias');
}

const linhas = slots.map((s, i) => (i + 1) + '. ' + s.label).join('\n');
const mensagemOpcoes = 'Otimo! Veja os horarios disponiveis para nossa call:\n\n' + linhas + '\n\nResponda com 1, 2 ou 3 para confirmar o horario de sua preferencia.';

return [{
  json: {
    telefone,
    nome,
    slots,
    slotsJson: JSON.stringify(slots),
    mensagemOpcoes
  }
}];

const data = $json.body;
const telefone = data.telefone;
const nome = data.nome;
const emailLead = data.email || '';
const mensagem = (data.mensagem || '').trim().toLowerCase();

let slots = [];
try {
  const raw = data.slots_proposto;
  if (Array.isArray(raw)) {
    slots = raw;
  } else {
    slots = JSON.parse(raw || '[]');
  }
} catch(e) {
  slots = [];
}

// Checar pedidoOutroDia ANTES de extrair indice para evitar
// falso-positivo: 'segunda' como 'segunda-feira' vs 'segunda opcao'
const pedidoOutroDia = /outro\s*dia|outra\s*data|outros\s*hor[aá]rios|outros\s*dias|semana\s*que\s*vem|pr[oó]xima\s*semana|diferente|tem\s*(mais|outro|outros)|h[aá]\s*(outro|outros)|existem?\s*(outro|outros)/.test(mensagem) ||
  /\b(segunda|ter[çc]a|quarta|quinta|sexta|s[aá]bado)\b/.test(mensagem);

let indiceEscolha = -1;
if (!pedidoOutroDia) {
  if (/\b1\b|primeiro|primeira/.test(mensagem)) indiceEscolha = 0;
  else if (/\b2\b|segundo|segunda/.test(mensagem)) indiceEscolha = 1;
  else if (/\b3\b|terceiro|terceira/.test(mensagem)) indiceEscolha = 2;
}

const escolhaValida = indiceEscolha >= 0 && indiceEscolha < slots.length;

if (!escolhaValida) {
  const linhas = slots.map((s, i) => (i + 1) + '. ' + s.label).join('\n');
  return [{ json: { telefone, nome, emailLead, escolhaValida: false, pedidoOutroDia, slotsTexto: linhas, slots_proposto: data.slots_proposto } }];
}

const slotEscolhido = slots[indiceEscolha];
const OFFSET_MS = 3 * 60 * 60 * 1000;

function toBRTLocal(isoUTC) {
  const d = new Date(new Date(isoUTC).getTime() - OFFSET_MS);
  return d.toISOString().slice(0, 19);
}

const eventoTitulo = 'Call Hive - ' + nome;
const mensagemConfirmacao = 'Perfeito! Call agendada para ' + slotEscolhido.label + '.\n\nAte la! Se tiver qualquer duvida, e so me chamar aqui';

return [{
  json: {
    telefone, nome, escolhaValida: true, eventoTitulo,
    eventoInicio: toBRTLocal(slotEscolhido.isoUTC),
    eventoFim: toBRTLocal(slotEscolhido.isoFimUTC),
    slotLabel: slotEscolhido.label, mensagemConfirmacao, emailLead
  }
}];

