const OFFSET_MS = 3 * 60 * 60 * 1000;
const data = $json;
const telefone = data.telefone;
const nome = data.nome;
const emailLead = data.emailLead || '';

let slotsAtuais = [];
try {
  slotsAtuais = JSON.parse(data.slots_proposto || '[]');
} catch(e) {
  slotsAtuais = [];
}

const diasExcluidos = new Set();
slotsAtuais.forEach(s => {
  const brt = new Date(new Date(s.isoUTC).getTime() - OFFSET_MS);
  diasExcluidos.add(brt.toISOString().slice(0, 10));
});

const agora = new Date();
const agoraBRT = new Date(agora.getTime() - OFFSET_MS);
const amanhaBRT = new Date(agoraBRT);
amanhaBRT.setDate(amanhaBRT.getDate() + 1);
amanhaBRT.setHours(0, 0, 0, 0);
const inicioJanela = new Date(amanhaBRT.getTime() + OFFSET_MS);
const fimJanela = new Date(inicioJanela.getTime() + 14 * 24 * 60 * 60 * 1000);

return [{
  json: {
    telefone, nome, emailLead,
    janelaInicio: inicioJanela.toISOString(),
    janelaFim: fimJanela.toISOString(),
    diasExcluidos: Array.from(diasExcluidos)
  }
}];

const OFFSET_MS = 3 * 60 * 60 * 1000;
const DURACAO_MS = 60 * 60 * 1000;
const BUSINESS = { 1:[9,30,22,30], 2:[9,30,22,30], 3:[9,30,22,30], 4:[9,30,22,30], 5:[9,30,22,30], 6:[9,30,17,0] };

const preparaData = $('Prepara Nova Janela').first().json;
const telefone = preparaData.telefone;
const nome = preparaData.nome;
const janelaInicio = new Date(preparaData.janelaInicio);
const janelaFim = new Date(preparaData.janelaFim);
const emailLead = preparaData.emailLead || '';
const diasExcluidos = new Set(preparaData.diasExcluidos || []);

const googleResp = $('FreeBusy Nova Janela').first().json;
const googleCal = (googleResp.calendars && (googleResp.calendars['wostki@gmail.com'] || googleResp.calendars.primary)) || {};
const googleBusy = (googleCal.busy || []).map(b => ({ start: b.start, end: b.end }));

// Nespon: se dateTime ja tem timezone (Z ou +/-HH:MM), usar direto; se nao, +3h (BRT como UTC)
function adjustNespon(obj) {
  const dateStr = obj.dateTime || obj.date;
  if (!dateStr) return null;
  const ms = new Date(dateStr).getTime();
  if (!obj.timeZone || obj.timeZone === 'UTC') return ms + OFFSET_MS;
  return ms;
}

const nesponEvents = $('Get Nespon Nova Janela').all();
const nesponBusy = nesponEvents
  .filter(e => e.json && e.json.start && e.json.end)
  .map(e => {
    const startMs = adjustNespon(e.json.start);
    const endMs = adjustNespon(e.json.end);
    if (!startMs || !endMs) return null;
    return {
      start: new Date(startMs).toISOString(),
      end:   new Date(endMs).toISOString()
    };
  })
  .filter(Boolean);

const allBusy = [...googleBusy, ...nesponBusy];

function isBusy(s, e) { return allBusy.some(b => s.getTime() < new Date(b.end).getTime() && e.getTime() > new Date(b.start).getTime()); }
function toBRT(d) { return new Date(d.getTime() - OFFSET_MS); }
function toUTC(d) { return new Date(d.getTime() + OFFSET_MS); }

const DIAS = ['Dom','Seg','Ter','Qua','Qui','Sex','Sab'];
const MESES = ['Jan','Fev','Mar','Abr','Mai','Jun','Jul','Ago','Set','Out','Nov','Dez'];
const slots = [];
let cursor = new Date(janelaInicio);

while (cursor < janelaFim && slots.length < 3) {
  const brtCursor = toBRT(cursor);
  const diaSemana = brtCursor.getDay();
  const diaStr = brtCursor.toISOString().slice(0, 10);

  if (diasExcluidos.has(diaStr) || !BUSINESS[diaSemana]) {
    const next = new Date(brtCursor); next.setDate(next.getDate()+1); next.setHours(0,0,0,0);
    cursor = toUTC(next); continue;
  }

  const [hI,mI,hF,mF] = BUSINESS[diaSemana];
  const brtDay = new Date(brtCursor); brtDay.setHours(0,0,0,0);
  const brtIni = new Date(brtDay); brtIni.setHours(hI,mI,0,0);
  const brtFim = new Date(brtDay); brtFim.setHours(hF,mF,0,0);

  if (brtCursor < brtIni) { cursor = toUTC(brtIni); continue; }
  if (brtCursor >= brtFim) {
    const next = new Date(brtDay); next.setDate(next.getDate()+1); next.setHours(0,0,0,0);
    cursor = toUTC(next); continue;
  }

  const slotStart = new Date(cursor);
  const slotEnd = new Date(cursor.getTime() + DURACAO_MS);

  if (slotEnd > toUTC(brtFim)) {
    const next = new Date(brtDay); next.setDate(next.getDate()+1); next.setHours(0,0,0,0);
    cursor = toUTC(next); continue;
  }

  if (!isBusy(slotStart, slotEnd)) {
    const bs = toBRT(slotStart);
    const label = DIAS[bs.getDay()] + ' ' + String(bs.getDate()).padStart(2,'0') + '/' + MESES[bs.getMonth()] + ' as ' + String(bs.getHours()).padStart(2,'0') + ':' + String(bs.getMinutes()).padStart(2,'0') + 'h';
    slots.push({ isoUTC: slotStart.toISOString(), isoFimUTC: slotEnd.toISOString(), label });
  }
  cursor = new Date(cursor.getTime() + 30*60*1000);
}

if (slots.length === 0) throw new Error('Nenhum slot em dias alternativos na janela de 14 dias');

const linhas = slots.map((s,i) => (i+1) + '. ' + s.label).join('\n');
const mensagemOpcoes = 'Claro! Aqui estao opcoes em outros dias:\n\n' + linhas + '\n\nResponda com 1, 2 ou 3 para confirmar.';
return [{ json: { telefone, nome, slots, slotsJson: JSON.stringify(slots), mensagemOpcoes, emailLead } }];

